import React from "react";
import { Link } from "react-router-dom";

function Home() {
  return (
    <div style={{ textAlign: "center", padding: "20px" }}>
      <h1>Welcome to ElectroStore</h1>
      <p>Shop the best electronics now!</p>
      <div style={{ display: "flex", justifyContent: "center", gap: "20px", marginTop: "20px" }}>
        <Link to="/category/phones"><button>Shop Phones</button></Link>
        <Link to="/category/headphones"><button>Shop Headphones</button></Link>
        <Link to="/category/ps5"><button>Shop PS5</button></Link>
      </div>
    </div>
  );
}

export default Home;
